SELECT ir.*, dv.generic_name as vaccine_name
FROM immunization_records ir
LEFT JOIN drugs_vaccines dv ON ir.vaccine_id = dv.id


        (ir.ear_tag LIKE CONCAT('%', #{search}, '%')
        OR dv.generic_name LIKE CONCAT('%', #{search}, '%'))


        AND dv.generic_name = #{vaccine}


        AND ir.event_time >= #{dateFrom}


        AND ir.event_time <= #{dateTo}


ORDER BY ir.event_time DESC
LIMIT #{size} OFFSET #{offset}

